const int NUM_WEIGHTS = 42;
const int NUM_IMAGES = 1;

int main() {
    printf("============================================================\n");
    printf("resnet18 C-Simulation (T=%d)\n", T_STEPS);
    printf("============================================================\n");
    printf("DDR_SIZE = %d elements (%.1f MB)\n", DDR_SIZE, DDR_SIZE * 4.0 / 1024 / 1024);
    printf("Weights = %d files\n\n", NUM_WEIGHTS);

    ap_int<32>* ddr = (ap_int<32>*)malloc(DDR_SIZE * sizeof(ap_int<32>));
    float* input_buf = (float*)malloc(INPUT_SIZE * sizeof(float));
    if (!ddr || !input_buf) { printf("FATAL: malloc failed\n"); return 1; }

    int correct = 0;
    int hls_pt_match = 0;
    float total_l2 = 0.0f;

    for (int idx = 0; idx < NUM_IMAGES; idx++) {
        // Load true label
        char path[256];
        snprintf(path, 256, "test_images/label_%d.bin", idx);
        FILE* fp = fopen(path, "rb");
        if (!fp) { printf("FATAL: missing %s\n", path); return 1; }
        int true_label;
        fread(&true_label, sizeof(int), 1, fp);
        fclose(fp);

        // Load input image
        snprintf(path, 256, "test_images/test_image_%d.bin", idx);
        fp = fopen(path, "rb");
        if (!fp) { printf("FATAL: missing %s\n", path); return 1; }
        fread(input_buf, sizeof(float), INPUT_SIZE, fp);
        fclose(fp);

        // Load expected (PyTorch T=4, mean of per-step outputs)
        snprintf(path, 256, "test_images/expected_output_%d.bin", idx);
        float expected_output[NUM_CLASSES];
        fp = fopen(path, "rb");
        if (!fp) { printf("FATAL: missing %s\n", path); return 1; }
        fread(expected_output, sizeof(float), NUM_CLASSES, fp);
        fclose(fp);

        printf("\n--- Image %d/1 (true label=%d) ---\n", idx + 1, true_label);

        // Zero DDR (resets LIF membrane states) and load weights once
        memset(ddr, 0, DDR_SIZE * sizeof(ap_int<32>));
        for (int w = 0; w < NUM_WEIGHTS; w++) {
            fp = fopen(WEIGHTS[w].filename, "rb");
            if (!fp) { printf("FATAL: Cannot open %s\n", WEIGHTS[w].filename); return 1; }
            fread((char*)ddr + WEIGHTS[w].byte_offset, 1, WEIGHTS[w].byte_size, fp);
            fclose(fp);
        }

        // T-step loop: membrane states persist in DDR top_level buffers
        // across control() calls (mirrors spikingjelly reset_net + T-loop).
        float acc_output[NUM_CLASSES] = {0.0f};
        for (int t = 0; t < T_STEPS; t++) {
            // Reload input each step: control() may clobber the input region
            float* ddr_f = (float*)((char*)ddr + INPUT_OFFSET * sizeof(ap_int<32>));
            for (int i = 0; i < INPUT_SIZE; i++) ddr_f[i] = input_buf[i];

            control(ddr, ddr, ddr);

            float* step_output = (float*)((char*)ddr + OUTPUT_OFFSET * sizeof(ap_int<32>));
            for (int i = 0; i < NUM_CLASSES; i++) acc_output[i] += step_output[i];
        }

        // spikingjelly convention: mean over T steps
        float hls_output[NUM_CLASSES];
        for (int i = 0; i < NUM_CLASSES; i++) hls_output[i] = acc_output[i] / T_STEPS;

        int hls_pred = 0;
        for (int i = 1; i < NUM_CLASSES; i++)
            if (hls_output[i] > hls_output[hls_pred]) hls_pred = i;

        // PyTorch prediction
        int pt_pred = 0;
        for (int i = 1; i < NUM_CLASSES; i++)
            if (expected_output[i] > expected_output[pt_pred]) pt_pred = i;

        // Compare HLS vs PyTorch
        float l2 = 0.0f, max_diff = 0.0f;
        for (int i = 0; i < NUM_CLASSES; i++) {
            float d = fabs(hls_output[i] - expected_output[i]);
            l2 += d * d;
            if (d > max_diff) max_diff = d;
        }
        l2 = sqrt(l2);
        total_l2 += l2;

        bool pred_correct = (hls_pred == true_label);
        if (pred_correct) correct++;
        if (hls_pred == pt_pred) hls_pt_match++;

        printf("  HLS  pred=%d, PyT pred=%d, true=%d  %s%s\n",
               hls_pred, pt_pred, true_label,
               pred_correct ? "PASS" : "FAIL",
               pred_correct && hls_pred == pt_pred ? "" : " (check)");

        // Print full output if there's disagreement
        if (l2 > 0.01f) {
            printf("  HLS out: ");
            for (int i = 0; i < NUM_CLASSES; i++) printf("%+.4f ", hls_output[i]);
            printf("\n  PyT out: ");
            for (int i = 0; i < NUM_CLASSES; i++) printf("%+.4f ", expected_output[i]);
            printf("\n");
        }
        printf("  L2=%.4f, max_diff=%.4f\n", l2, max_diff);
    }

    printf("\n============================================================\n");
    printf("RESULTS (T=%d):\n", T_STEPS);
    printf("  Accuracy:    %d/%d (%.1f%%)\n", correct, NUM_IMAGES, 100.0 * correct / NUM_IMAGES);
    printf("  HLS==PyT:    %d/%d (%.1f%%)\n", hls_pt_match, NUM_IMAGES, 100.0 * hls_pt_match / NUM_IMAGES);
    printf("  Avg L2:      %.4f\n", total_l2 / NUM_IMAGES);
    printf("============================================================\n");

    free(input_buf);
    free(ddr);
    return (correct == NUM_IMAGES && hls_pt_match == NUM_IMAGES) ? 0 : 1;
}
